const BY_CODE: Record<string, Airport> = Object.fromEntries(AIRPORTS.map((a) => [a.code, a]));

export function getAirport(code: string): Airport | undefined {
  return BY_CODE[code?.toUpperCase?.()];
}

/** Resolve free text (a 3-letter code, a city, or an airport name) to an IATA code. */
export function resolveAirport(input: string): Airport | undefined {
  if (!input) return undefined;
  // Autocomplete values look like "Goa (GOI)" — prefer an embedded IATA code.
  const paren = input.match(/\(([A-Za-z]{3})\)/);
  if (paren && BY_CODE[paren[1].toUpperCase()]) return BY_CODE[paren[1].toUpperCase()];
  const q = input.trim().toUpperCase();
  if (BY_CODE[q]) return BY_CODE[q];
  const lc = input.trim().toLowerCase();
  return (
    AIRPORTS.find((a) => a.city.toLowerCase() === lc) ||
    AIRPORTS.find((a) => a.city.toLowerCase().startsWith(lc)) ||
    AIRPORTS.find((a) => a.name.toLowerCase().includes(lc) || a.city.toLowerCase().includes(lc))
  );
}
